column.value:
{
                "pageDescription": "Data Analysis and Export",
                "dataPoints": {
                    "analysisDetails": {
                        "softwareUsed": {
                            "type": "text",
                            "label": "Software Used",
                            "required": false
                        },
                        "analystName": {
                            "type": "text",
                            "label": "Analyst Name",
                            "required": true
                        },
                        "analysisDate": {
                            "type": "date",
                            "label": "Analysis Date",
                            "required": true
                        },
                        "analysisNotes": {
                            "type": "text",
                            "label": "Notes",
                            "multiline": true,
                            "required": false
                        }
                    },
                    "validationStatus": {
                        "status": {
                            "type": "choice",
                            "label": "Validation Status",
                            "options": ["VALID", "INVALID", "INCONCLUSIVE"],
                            "required": true
                        },
                        "reason": {
                            "type": "text",
                            "label": "Reason",
                            "conditionalOn": "status != VALID",
                            "required": false
                        }
                    },
                    "exportOptions": {
                        "exportFormat": {
                            "type": "choice",
                            "label": "Export Format",
                            "options": ["Excel (XLSX)", "CSV"],
                            "required": false
                        },
                        "dataType": {
                            "type": "choice",
                            "label": "Data Type",
                            "options": ["Raw", "Processed"],
                            "required": false
                        }
                    },
                    "delivery": {
                        "recipientName": {
                            "type": "text",
                            "label": "Recipient Name",
                            "required": false
                        },
                        "recipientEmail": {
                            "type": "text",
                            "label": "Recipient Email",
                            "required": false
                        }
                    }
                },
                "systemActions": [
                    "Flag samples with validation status",
                    "Export results to file",
                    "Record delivery history",
                    "Lock raw data (audit trail)",
                    "Send validated samples to Reporting page"
                ],
                "bulkOperations": {
                    "enabled": true,
                    "applyToSelected": ["validationStatus", "analysisDetails"]
                },
                "nextPage": "Reporting and REDCap Integration"
            }
